const GAS_GIANT    = 'X1-UX96-C41';
const ASTEROID     = 'X1-UX96-B12';
const FUEL_STATION = 'X1-UX96-B6';
const MIN_FUEL     = 280;
const SIPHON_RESOURCES = new Set([
  'POLYNUCLEOTIDES','HYDROCARBON','LIQUID_HYDROGEN',
  'LIQUID_NITROGEN','ATMOSPHERIC_GASES','AMMONIA_ICE'
]);

const staticData  = $getWorkflowStaticData('global');
const ships       = $('Get Ships').first().json.data   || [];
const conts       = $input.first().json.data            || [];
const activeC     = conts.find(c => c.accepted && !c.fulfilled) || null;
const pendingC    = conts.find(c => !c.accepted)                || null;
const tradeSym    = activeC?.terms?.deliver?.[0]?.tradeSymbol;
const deliverDest = activeC?.terms?.deliver?.[0]?.destinationSymbol;
const isSiphonContract = tradeSym && SIPHON_RESOURCES.has(tradeSym);
const workSite    = isSiphonContract ? GAS_GIANT : ASTEROID;

function getRole(ship) {
  const frame = ship.frame?.symbol || '';
  if (frame.includes('PROBE') || frame.includes('SATELLITE')) return null;
  if (frame.includes('FRIGATE')) return 'hauler';
  if ((ship.mounts || []).some(m => m.symbol?.includes('MINING_LASER'))) return 'miner';
  return null;
}
function hasSiphon(ship) {
  return (ship.mounts || []).some(m => m.symbol?.includes('GAS_SIPHON'));
}

let contractAccepted = false;

function decide(ship) {
  const nav      = ship.nav;
  const status   = nav.status;
  const wp       = nav.waypointSymbol;
  const flightMode = nav.flightMode || 'CRUISE';
  const fuel     = ship.fuel;
  const cargo    = ship.cargo;
  const now      = Date.now();
  const sym      = ship.symbol;

  const cooldownExp = new Date(ship.cooldown?.expiration || 0).getTime();
  if (cooldownExp > now)     return {action:'on_cooldown', ship:sym, until:ship.cooldown.expiration};
  if (status === 'IN_TRANSIT') return {action:'in_transit', ship:sym, status, wp};

  // No active contract — accept pending or idle
  if (!activeC) {
    if (pendingC && !contractAccepted) {
      contractAccepted = true;
      return {action:'accept_contract', ship:sym, contractId:pendingC.id};
    }
    const junk = cargo.inventory.filter(i => i.symbol !== tradeSym);
    if (junk.length > 0) return junk.map(i => ({action:'jettison', ship:sym, symbol:i.symbol, units:i.units}));
    return {action:'idle', ship:sym, status, wp, reason:'awaiting_contract'};
  }

  // Skip ships that can't work this contract type
  const canWork = isSiphonContract ? hasSiphon(ship) : true;
  if (!canWork) return {action:'idle', ship:sym, status, wp, reason:'wrong_tool_for_contract'};

  const cargoPct = cargo.units / cargo.capacity;
  const haveOre  = (cargo.inventory.find(i => i.symbol === tradeSym)?.units) ?? 0;
  const fuelFull = fuel.current >= fuel.capacity - 5;

  // Jettison junk when cargo filling up
  const junk = cargo.inventory.filter(i => i.symbol !== tradeSym);
  if (cargoPct >= 0.7 && junk.length > 0) {
    return junk.map(i => ({action:'jettison', ship:sym, symbol:i.symbol, units:i.units}));
  }

  // ── Deliver loop ──────────────────────────────────────────────────────────
  if (haveOre > 0) {
    if (wp === deliverDest) {
      if (status === 'DOCKED')   return {action:'deliver', ship:sym, contractId:activeC.id, units:haveOre, tradeSym};
      if (status === 'IN_ORBIT') return {action:'dock', ship:sym};
    }
    if (wp === FUEL_STATION) {
      if (status === 'IN_ORBIT' && fuelFull) {
        if (flightMode === 'DRIFT') return {action:'set_cruise', ship:sym};
        return {action:'navigate', ship:sym, waypoint:deliverDest, reason:'deliver'};
      }
      if (status === 'IN_ORBIT') return {action:'dock', ship:sym};
      if (status === 'DOCKED') {
        if (!fuelFull) return {action:'refuel', ship:sym};
        if (flightMode === 'DRIFT') return {action:'set_cruise', ship:sym};
        return {action:'orbit', ship:sym};
      }
    }
    if (fuel.current < MIN_FUEL && status === 'IN_ORBIT') {
      if (flightMode !== 'DRIFT') return {action:'set_drift', ship:sym};
      return {action:'navigate', ship:sym, waypoint:FUEL_STATION, reason:'refuel'};
    }
    if (status === 'IN_ORBIT') return {action:'navigate', ship:sym, waypoint:deliverDest, reason:'deliver'};
    if (status === 'DOCKED')   return {action:'orbit', ship:sym};
  }

  // ── Harvest loop ──────────────────────────────────────────────────────────
  if (wp !== workSite) {
    if (fuel.current < MIN_FUEL && status === 'IN_ORBIT') {
      if (flightMode !== 'DRIFT') return {action:'set_drift', ship:sym};
      return {action:'navigate', ship:sym, waypoint:FUEL_STATION, reason:'refuel'};
    }
    if (status === 'IN_ORBIT') return {action:'navigate', ship:sym, waypoint:workSite, reason:'harvest'};
    if (status === 'DOCKED')   return {action:'orbit', ship:sym};
  }

  // At work site
  if (status === 'DOCKED') return {action:'orbit', ship:sym};
  if (status === 'IN_ORBIT') {
    if (isSiphonContract) return {action:'siphon', ship:sym};
    const survey = staticData.survey;
    const surveyValid = survey && new Date(survey.expiration).getTime() > now;
    if (!surveyValid) return {action:'survey', ship:sym};
    return {action:'mine_survey', ship:sym, survey};
  }

  return {action:'idle', ship:sym, status, wp, reason:'unknown'};
}

const actions = [];
for (const ship of ships) {
  if (!getRole(ship)) continue;
  const result = decide(ship);
  if (!result) continue;
  if (Array.isArray(result)) {
    for (const item of result) actions.push({json: item});
  } else {
    actions.push({json: result});
  }
}
return actions.length > 0 ? actions : [{json:{action:'idle', reason:'no_active_ships'}}];

const staticData = $getWorkflowStaticData('global');
const result = $input.first().json;
const surveys = result.data?.surveys || [];

// Prefer survey that has contract ore deposits
const contractOre = 'ALUMINUM_ORE';
const best = surveys.find(s => s.deposits?.some(d => d.symbol === contractOre)) || surveys[0];

if (best) {
  staticData.survey = best;
  const ores = best.deposits.map(d => d.symbol).join(', ');
  return [{json:{stored:true, signature:best.signature, ores, expiration:best.expiration}}];
}
return [{json:{stored:false}}];

